import React, { useState, useEffect } from 'react';
import { collection, query, orderBy, getDocs } from 'firebase/firestore';
import { db } from '../firebase/config';

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchAttendees = async () => {
    setLoading(true);
    const q = query(collection(db, 'attendance'), orderBy('createdAt', 'desc'));
    const querySnapshot = await getDocs(q);
    const data = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    setAttendees(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchAttendees();
  }, []);

  const downloadCSV = () => {
    const headers = ['First Name', 'Last Name', 'Email', 'Phone', 'Category', 'Timestamp'];
    const rows = attendees.map(a => [
      a.firstName,
      a.lastName,
      a.email,
      a.phone,
      a.category,
      a.createdAt?.toDate().toLocaleString() || ''
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(e => e.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `tcn_igando_attendance_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="w-full max-w-5xl bg-white rounded-xl shadow-2xl p-8 animate-fade-in overflow-hidden">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Admin Dashboard</h2>
          <p className="text-slate-500 text-sm">Total Attendees: {attendees.length}</p>
        </div>
        <div className="flex gap-4">
          <button onClick={fetchAttendees} className="p-2 px-4 bg-slate-100 rounded-lg hover:bg-slate-200 text-slate-600 transition-all">
            <i className="fa-solid fa-rotate mr-2"></i> Refresh
          </button>
          <button onClick={downloadCSV} className="p-2 px-4 bg-[#5C6BC0] text-white rounded-lg hover:bg-[#4E5BA6] shadow-md transition-all">
            <i className="fa-solid fa-file-csv mr-2"></i> Export CSV
          </button>
        </div>
      </div>

      <div className="overflow-x-auto border rounded-xl">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold tracking-wider">
            <tr>
              <th className="px-6 py-4">Name</th>
              <th className="px-6 py-4">Contact</th>
              <th className="px-6 py-4">Category</th>
              <th className="px-6 py-4">Time</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {attendees.map(a => (
              <tr key={a.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4">
                  <div className="font-semibold text-slate-700">{a.firstName} {a.lastName}</div>
                </td>
                <td className="px-6 py-4">
                  <div className="text-sm text-slate-600">{a.email}</div>
                  <div className="text-xs text-slate-400">{a.phone}</div>
                </td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${a.category === 'Member' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>
                    {a.category}
                  </span>
                </td>
                <td className="px-6 py-4 text-xs text-slate-400">
                  {a.createdAt?.toDate().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </td>
              </tr>
            ))}
            {loading && <tr><td colSpan={4} className="text-center py-20 text-slate-400">Loading data...</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  );
};

