interface Props {
  onSuccess: (firstName: string) => void;
}

const AttendanceForm: React.FC<Props> = ({ onSuccess }) => {
  const [formData, setFormData] = useState<FormState>({
    firstName: '',
    lastName: '',
    phone: '',
    email: '',
    category: 'Member',
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [loading, setLoading] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.firstName.trim()) newErrors.firstName = 'Required';
    if (!formData.lastName.trim()) newErrors.lastName = 'Required';

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!formData.email.trim()) {
      newErrors.email = 'Required';
    } else if (!emailRegex.test(formData.email)) {
      newErrors.email = 'Invalid';
    }

    if (!formData.phone.trim()) newErrors.phone = 'Required';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setLoading(true);
    setSubmitError(null);

    try {
      // Fix: Use v8 collection.add syntax and firebase.firestore.FieldValue.serverTimestamp()
      await db.collection('attendance').add({
        ...formData,
        eventId: 'tcn-igando-crossover-2025',
        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      });
      onSuccess(formData.firstName);
    } catch (error: any) {
      console.error(error);
      setSubmitError('Failed to register. Please check your connection.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="w-full max-w-[600px] bg-white rounded-xl overflow-hidden shadow-2xl animate-fade-in">
      {/* Event Poster / Flyer */}
      <div className="aspect-square w-full bg-gray-200">
        <img 
          src="https://images.unsplash.com/photo-1465447142348-e9952c393450?q=80&w=1000&auto=format&fit=crop" 
          alt="Crossover 2025 Flyer" 
          className="w-full h-full object-cover"
        />
      </div>

      <div className="p-8 md:p-12 space-y-8">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">TCN Igando</h2>
          <p className="text-slate-500 text-sm mt-1">Crossover Service 2025</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-500">First Name</label>
              <input
                type="text"
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                placeholder="Joshua"
                className={`w-full px-4 py-3 rounded-lg bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none ${errors.firstName ? 'ring-2 ring-red-300' : ''}`}
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-500">Last Name</label>
              <input
                type="text"
                name="lastName"
                value={formData.lastName}
                onChange={handleChange}
                placeholder="Ehimare"
                className={`w-full px-4 py-3 rounded-lg bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none ${errors.lastName ? 'ring-2 ring-red-300' : ''}`}
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-500">Email Address</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="jcollehis@gmail.com"
              className={`w-full px-4 py-3 rounded-lg bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none ${errors.email ? 'ring-2 ring-red-300' : ''}`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-500">Phone Number</label>
            <input
              type="tel"
              name="phone"
              value={formData.phone}
              onChange={handleChange}
              placeholder="+2348187273947"
              className={`w-full px-4 py-3 rounded-lg bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none ${errors.phone ? 'ring-2 ring-red-300' : ''}`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-500">Category</label>
            <div className="relative">
              <select
                name="category"
