  const [aiMessage, setAiMessage] = useState<string>('');
  const [count, setCount] = useState(0);
  const [view, setView] = useState<'form' | 'admin'>('form');

  // Real-time listener using Modular SDK
  useEffect(() => {
    const q = query(collection(db, 'attendance'));
