        @keyframes bounceIn {
          0% { opacity: 0; transform: scale(0.9); }
          70% { transform: scale(1.02); }
          100% { opacity: 1; transform: scale(1); }
        }
        .animate-fade-in {
          animation: fadeIn 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
