import React, { useState } from 'react';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../firebase/config';
import { FormState, FormErrors } from '../types';

interface Props {
  onSuccess: (firstName: string) => void;
}

const AttendanceForm: React.FC<Props> = ({ onSuccess }) => {
  const [formData, setFormData] = useState<FormState>({
    firstName: '',
    lastName: '',
    phone: '',
    email: '',
    category: 'Member',
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [loading, setLoading] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    if (!formData.firstName.trim()) newErrors.firstName = 'Required';
    if (!formData.lastName.trim()) newErrors.lastName = 'Required';

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!formData.email.trim()) {
      newErrors.email = 'Required';
    } else if (!emailRegex.test(formData.email)) {
      newErrors.email = 'Invalid';
    }

    if (!formData.phone.trim()) newErrors.phone = 'Required';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setLoading(true);
    setSubmitError(null);

    try {
      const attendanceRef = collection(db, 'attendance');
      await addDoc(attendanceRef, {
        ...formData,
        eventId: 'tcn-igando-crossover-2025',
        createdAt: serverTimestamp(),
      });
      onSuccess(formData.firstName);
    } catch (error: any) {
      console.error(error);
      setSubmitError('Failed to register. Please check your connection.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="w-full bg-white rounded-2xl overflow-hidden shadow-2xl border border-white/60">
      <div className="p-8 md:p-12 space-y-8">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Crossover Attendance</h2>
          <p className="text-slate-400 text-sm mt-1 font-medium">Please fill in your details to check-in.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">First Name</label>
              <input
                type="text"
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                placeholder="Joshua"
                className={`w-full px-4 py-4 rounded-xl bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-medium ${errors.firstName ? 'ring-2 ring-red-300' : ''}`}
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Last Name</label>
              <input
                type="text"
                name="lastName"
                value={formData.lastName}
                onChange={handleChange}
                placeholder="Ehimare"
                className={`w-full px-4 py-4 rounded-xl bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-medium ${errors.lastName ? 'ring-2 ring-red-300' : ''}`}
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Email Address</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="jcollehis@gmail.com"
              className={`w-full px-4 py-4 rounded-xl bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-medium ${errors.email ? 'ring-2 ring-red-300' : ''}`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Phone Number</label>
            <input
              type="tel"
              name="phone"
              value={formData.phone}
              onChange={handleChange}
              placeholder="+2348187273947"
              className={`w-full px-4 py-4 rounded-xl bg-[#E8F0FE] text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-medium ${errors.phone ? 'ring-2 ring-red-300' : ''}`}
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider ml-1">Category</label>
            <div className="relative">
              <select
                name="category"
                value={formData.category}
                onChange={handleChange}
                className="w-full px-4 py-4 rounded-xl bg-[#F3E8FF] text-slate-700 outline-none appearance-none font-bold border-none"
              >
                <option value="Member">Member</option>
                <option value="First Timer/Guest">First Timer/Guest</option>
              </select>
              <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-slate-500">
                <i className="fa-solid fa-chevron-down text-xs"></i>
              </div>
            </div>
          </div>

          {submitError && <p className="text-red-500 text-xs font-bold text-center bg-red-50 p-3 rounded-lg border border-red-100">{submitError}</p>}

          <button
            type="submit"
            disabled={loading}
            className={`w-full py-5 rounded-xl font-black text-white transition-all shadow-xl active:scale-[0.98] text-base uppercase tracking-widest ${
              loading ? 'bg-indigo-400 cursor-not-allowed' : 'bg-[#5C6BC0] hover:bg-[#4E5BA6] hover:shadow-indigo-200'
            }`}
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                Processing...
              </span>
            ) : 'Submit Attendance'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AttendanceForm;

import React, { useState, useEffect } from 'react';
import { collection, query, orderBy, getDocs } from 'firebase/firestore';
import { db } from '../firebase/config';

const ADMIN_PASSWORD = 'IGANDO_ADMIN_2025'; // Simple hardcoded password for access

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);

  const fetchAttendees = async () => {
    setLoading(true);
    try {
      const attendanceRef = collection(db, 'attendance');
      const q = query(attendanceRef, orderBy('createdAt', 'desc'));
      const querySnapshot = await getDocs(q);
      const data = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setAttendees(data);
    } catch (error) {
      console.error("Error fetching attendees:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchAttendees();
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      setAuthError(false);
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  const downloadCSV = () => {
    const headers = ['First Name', 'Last Name', 'Email', 'Phone', 'Category', 'Timestamp'];
    const rows = attendees.map(a => [
      a.firstName,
      a.lastName,
      a.email,
      a.phone,
      a.category,
      a.createdAt?.toDate().toLocaleString() || ''
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(e => e.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `tcn_igando_attendance_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (!isAuthenticated) {
    return (
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-10 animate-fade-in border border-white/60 text-center">
        <div className="w-20 h-20 bg-indigo-50 text-[#5C6BC0] rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-4 ring-indigo-50/50">
          <i className="fa-solid fa-lock text-3xl"></i>
        </div>
        <h2 className="text-2xl font-black text-slate-800 mb-2">Restricted Area</h2>
        <p className="text-slate-400 text-sm mb-8 font-medium">Please enter the administrator password to view attendance records.</p>

        <form onSubmit={handleLogin} className="space-y-4">
          <input
            type="password"
            value={passwordInput}
            onChange={(e) => setPasswordInput(e.target.value)}
            placeholder="Enter Password"
            className={`w-full px-5 py-4 rounded-xl bg-slate-50 text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-bold text-center tracking-widest ${authError ? 'ring-2 ring-red-400' : ''}`}
            autoFocus
          />
          {authError && <p className="text-red-500 text-[10px] font-black uppercase tracking-widest animate-pulse">Access Denied</p>}
          <button
            type="submit"
            className="w-full py-4 bg-[#5C6BC0] text-white rounded-xl font-black hover:bg-[#4E5BA6] transition-all shadow-lg active:scale-95 uppercase tracking-widest"
          >
            Unlock Dashboard
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="w-full max-w-5xl bg-white rounded-xl shadow-2xl p-8 animate-fade-in overflow-hidden border border-white/60">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Admin Portal</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="flex h-2 w-2 rounded-full bg-green-500"></span>
            <p className="text-slate-400 text-sm font-bold uppercase tracking-widest">{attendees.length} Verified Check-ins</p>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
