import React, { useState, useEffect } from 'react';
import { collection, query, orderBy, getDocs, writeBatch, doc } from 'firebase/firestore';
import { db } from '../firebase/config';

const ADMIN_PASSWORD = 'IGANDO_ADMIN_2025'; // Simple hardcoded password for access

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);

  const fetchAttendees = async () => {
    setLoading(true);
    try {
      const attendanceRef = collection(db, 'attendance');
      const q = query(attendanceRef, orderBy('createdAt', 'desc'));
      const querySnapshot = await getDocs(q);
      const data = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setAttendees(data);
    } catch (error) {
      console.error("Error fetching attendees:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchAttendees();
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      setAuthError(false);
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  const handleClearAll = async () => {
    if (attendees.length === 0) return;

    const confirmDelete = window.confirm(
      `WARNING: This will permanently delete ALL ${attendees.length} records from the database. This action cannot be undone. Are you sure?`
    );

    if (!confirmDelete) return;

    setActionLoading(true);
    try {
      const batch = writeBatch(db);
      attendees.forEach((attendee) => {
        const docRef = doc(db, 'attendance', attendee.id);
        batch.delete(docRef);
      });

      await batch.commit();
      setAttendees([]); // Clear local state immediately
      alert("All records have been successfully cleared.");
    } catch (error) {
      console.error("Error clearing records:", error);
      alert("Failed to clear records. Please check your permissions.");
    } finally {
      setActionLoading(false);
    }
  };

  const downloadCSV = () => {
    if (attendees.length === 0) return;
    const headers = ['First Name', 'Last Name', 'Email', 'Phone', 'Category', 'Timestamp'];
    const rows = attendees.map(a => [
      `"${a.firstName}"`,
      `"${a.lastName}"`,
      `"${a.email}"`,
      `"${a.phone}"`,
      `"${a.category}"`,
      `"${a.createdAt?.toDate().toLocaleString() || ''}"`
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(e => e.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `tcn_igando_attendance_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (!isAuthenticated) {
    return (
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-10 animate-fade-in border border-white/60 text-center">
        <div className="w-20 h-20 bg-indigo-50 text-[#5C6BC0] rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-4 ring-indigo-50/50">
          <i className="fa-solid fa-lock text-3xl"></i>
        </div>
        <h2 className="text-2xl font-black text-slate-800 mb-2">Restricted Area</h2>
        <p className="text-slate-400 text-sm mb-8 font-medium">Please enter the administrator password to view attendance records.</p>

        <form onSubmit={handleLogin} className="space-y-4">
          <input
            type="password"
            value={passwordInput}
            onChange={(e) => setPasswordInput(e.target.value)}
            placeholder="Enter Password"
            className={`w-full px-5 py-4 rounded-xl bg-slate-50 text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-bold text-center tracking-widest ${authError ? 'ring-2 ring-red-400' : ''}`}
            autoFocus
          />
          {authError && <p className="text-red-500 text-[10px] font-black uppercase tracking-widest animate-pulse">Access Denied</p>}
          <button
            type="submit"
            className="w-full py-4 bg-[#5C6BC0] text-white rounded-xl font-black hover:bg-[#4E5BA6] transition-all shadow-lg active:scale-95 uppercase tracking-widest"
          >
            Unlock Dashboard
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="w-full max-w-5xl bg-white rounded-xl shadow-2xl p-8 animate-fade-in overflow-hidden border border-white/60">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 mb-10">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Admin Portal</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className={`flex h-2.5 w-2.5 rounded-full ${attendees.length > 0 ? 'bg-green-500 animate-pulse' : 'bg-slate-300'}`}></span>
            <p className="text-slate-400 text-sm font-bold uppercase tracking-widest">
              {attendees.length} Verified Check-ins
            </p>
          </div>
        </div>
        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <button 
            onClick={fetchAttendees} 
            disabled={loading || actionLoading}
            className="flex-1 lg:flex-none p-3 px-5 bg-slate-50 rounded-xl hover:bg-slate-100 text-slate-600 font-bold text-xs transition-all flex items-center justify-center gap-2 disabled:opacity-50"
          >
            <i className={`fa-solid fa-rotate text-[10px] ${loading ? 'animate-spin' : ''}`}></i> Refresh
          </button>

          <button 
            onClick={downloadCSV} 
            disabled={attendees.length === 0 || actionLoading}
            className="flex-1 lg:flex-none p-3 px-6 bg-[#5C6BC0] text-white rounded-xl font-bold hover:bg-[#4E5BA6] shadow-md transition-all text-xs flex items-center justify-center gap-2 uppercase tracking-widest disabled:bg-slate-200 disabled:shadow-none"
          >
            <i className="fa-solid fa-file-csv"></i> Export CSV
          </button>

          <button 
            onClick={handleClearAll} 
            disabled={attendees.length === 0 || actionLoading}
            className="flex-1 lg:flex-none p-3 px-6 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 shadow-md transition-all text-xs flex items-center justify-center gap-2 uppercase tracking-widest disabled:bg-slate-200 disabled:shadow-none"
          >
            {actionLoading ? (
               <i className="fa-solid fa-circle-notch animate-spin"></i>
            ) : (
               <i className="fa-solid fa-trash-can"></i>
            )}
            Clear All
          </button>
        </div>
      </div>

      <div className="overflow-x-auto border border-slate-100 rounded-2xl">
        <table className="w-full text-left border-collapse">
          <thead className="bg-slate-50/50 text-slate-400 uppercase text-[10px] font-black tracking-[0.15em]">
            <tr>
              <th className="px-8 py-5">Attendee Name</th>
              <th className="px-8 py-5">Contact Details</th>
              <th className="px-8 py-5">Category</th>
              <th className="px-8 py-5">Check-in Time</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {attendees.map(a => (
              <tr key={a.id} className="hover:bg-slate-50/40 transition-colors">
                <td className="px-8 py-6">
                  <div className="font-bold text-slate-700 text-sm">{a.firstName} {a.lastName}</div>
                </td>
                <td className="px-8 py-6">
                  <div className="text-xs font-bold text-slate-500">{a.email}</div>
                  <div className="text-[10px] text-slate-400 font-medium mt-0.5">{a.phone}</div>
                </td>
                <td className="px-8 py-6">
                  <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider ${a.category === 'Member' ? 'bg-green-50 text-green-600 border border-green-100' : 'bg-orange-50 text-orange-600 border border-orange-100'}`}>
                    {a.category}
                  </span>
                </td>
                <td className="px-8 py-6 text-[11px] font-bold text-slate-400">
                  {a.createdAt?.toDate() ? a.createdAt.toDate().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }) : 'Pending'}
                </td>
              </tr>
            ))}
            {loading && <tr><td colSpan={4} className="text-center py-24">
              <div className="flex flex-col items-center gap-4">
                <i className="fa-solid fa-circle-notch animate-spin text-2xl text-indigo-300"></i>
                <span className="text-xs font-black text-slate-300 uppercase tracking-widest">Synchronizing Records...</span>
