import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, getDocs, writeBatch, doc } from 'firebase/firestore';
import { db } from '../firebase/config';

const ADMIN_PASSWORD = 'IGANDO_ADMIN_2025';

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [authError, setAuthError] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const fetchAttendees = async () => {
    setLoading(true);
    setFetchError(null);
    try {
      const attendanceRef = collection(db, 'attendance');
      const q = query(attendanceRef, orderBy('createdAt', 'desc'));
      const querySnapshot = await getDocs(q);
      const data = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setAttendees(data);
    } catch (error) {
      console.error("Error fetching attendees:", error);
      setFetchError("Synchronization interrupted. Please check your connection.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isAuthenticated) {
      fetchAttendees();
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      setAuthError(false);
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  // Advanced Filtering
  const filteredAttendees = useMemo(() => {
    if (!searchQuery.trim()) return attendees;
    const lowerQuery = searchQuery.toLowerCase();
    return attendees.filter(a => 
      a.firstName?.toLowerCase().includes(lowerQuery) ||
      a.lastName?.toLowerCase().includes(lowerQuery) ||
      a.email?.toLowerCase().includes(lowerQuery) ||
      a.phone?.includes(lowerQuery)
    );
  }, [searchQuery, attendees]);

  // Stats Calculation
  const stats = useMemo(() => {
    const members = attendees.filter(a => a.category === 'Member').length;
    const guests = attendees.length - members;
    return { members, guests };
  }, [attendees]);

  const handleClearAll = async () => {
    if (attendees.length === 0) return;

    const confirm1 = window.confirm(`Are you sure you want to delete ALL ${attendees.length} records?`);
    if (!confirm1) return;

    const confirm2 = window.confirm(`FINAL WARNING: This action is permanent and cannot be undone. Clear everything?`);
    if (!confirm2) return;

    setActionLoading(true);
    try {
      const batch = writeBatch(db);
      attendees.forEach((attendee) => {
        const docRef = doc(db, 'attendance', attendee.id);
        batch.delete(docRef);
      });

      await batch.commit();
      setAttendees([]);
      alert("Database cleared successfully.");
    } catch (error) {
      console.error("Clear error:", error);
      alert("Failed to clear records. Check permissions.");
    } finally {
      setActionLoading(false);
    }
  };

  const copyEmails = () => {
    const emails = attendees.map(a => a.email).filter(Boolean).join(', ');
    navigator.clipboard.writeText(emails);
    alert("Email addresses copied to clipboard!");
  };

  const downloadCSV = () => {
    if (attendees.length === 0) return;
    const headers = ['First Name', 'Last Name', 'Email', 'Phone', 'Category', 'Timestamp'];
    const rows = attendees.map(a => [
      `"${a.firstName}"`, `"${a.lastName}"`, `"${a.email}"`, `"${a.phone}"`, `"${a.category}"`, 
      `"${a.createdAt?.toDate().toLocaleString() || ''}"`
    ]);
    const csvContent = [headers.join(','), ...rows.map(e => e.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `tcn_attendance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  if (!isAuthenticated) {
    return (
      <div className="w-full max-w-md bg-white rounded-[2rem] shadow-2xl p-10 animate-fade-in border border-white/60 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-500 to-purple-500"></div>
        <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-8 rotate-3 shadow-lg">
          <i className="fa-solid fa-shield-halved text-3xl"></i>
        </div>
        <h2 className="text-2xl font-black text-slate-800 mb-2">Admin Security</h2>
        <p className="text-slate-400 text-sm mb-8 font-medium">Identify yourself to access the database.</p>

        <form onSubmit={handleLogin} className="space-y-4">
          <div className="relative group">
            <input
              type={showPassword ? "text" : "password"}
              value={passwordInput}
              onChange={(e) => setPasswordInput(e.target.value)}
              placeholder="System Password"
              className={`w-full px-6 py-4 rounded-2xl bg-slate-50 text-slate-700 outline-none focus:ring-2 focus:ring-indigo-300 transition-all border-none font-bold text-center tracking-widest ${authError ? 'ring-2 ring-red-400' : ''}`}
              autoFocus
            />
            <button 
              type="button" 
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 transition-colors"
            >
              <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
            </button>
          </div>
          {authError && <p className="text-red-500 text-[10px] font-black uppercase tracking-widest animate-pulse">Incorrect credentials</p>}
          <button
            type="submit"
            className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 transition-all shadow-xl active:scale-95 uppercase tracking-widest"
          >
            Authorize Access
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="w-full max-w-6xl bg-white rounded-3xl shadow-2xl p-8 animate-fade-in border border-white/60">
      {/* Header & Stats */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-10">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tight">Admin Portal</h2>
          <div className="flex flex-wrap items-center gap-4 mt-3">
            <div className="flex items-center gap-2 bg-indigo-50 px-3 py-1.5 rounded-full border border-indigo-100">
              <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
              <span className="text-[10px] font-black text-indigo-600 uppercase tracking-wider">{attendees.length} Total</span>
            </div>
            <div className="flex items-center gap-2 bg-green-50 px-3 py-1.5 rounded-full border border-green-100">
              <span className="text-[10px] font-black text-green-600 uppercase tracking-wider">{stats.members} Members</span>
            </div>
            <div className="flex items-center gap-2 bg-orange-50 px-3 py-1.5 rounded-full border border-orange-100">
              <span className="text-[10px] font-black text-orange-600 uppercase tracking-wider">{stats.guests} Guests</span>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <button onClick={copyEmails} className="flex-1 lg:flex-none p-3 px-5 bg-slate-50 rounded-xl hover:bg-slate-100 text-slate-600 font-bold text-[10px] transition-all flex items-center justify-center gap-2 uppercase">
            <i className="fa-solid fa-envelope"></i> Copy Emails
          </button>
          <button onClick={downloadCSV} className="flex-1 lg:flex-none p-3 px-5 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg transition-all text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest">
            <i className="fa-solid fa-file-csv"></i> Export CSV
          </button>
          <button onClick={handleClearAll} disabled={actionLoading} className="flex-1 lg:flex-none p-3 px-5 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 shadow-lg transition-all text-[10px] flex items-center justify-center gap-2 uppercase tracking-widest disabled:opacity-50">
            {actionLoading ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-trash-can"></i>} Clear All
          </button>
        </div>
      </div>

      {/* Search Bar */}
      <div className="relative mb-8 group">
        <i className="fa-solid fa-magnifying-glass absolute left-6 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors"></i>
        <input 
          type="text" 
          placeholder="Search by name, email or phone..." 
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full pl-14 pr-6 py-5 rounded-2xl bg-slate-50 border-2 border-transparent focus:border-indigo-100 focus:bg-white text-slate-700 outline-none transition-all font-bold placeholder:text-slate-300 placeholder:font-medium shadow-inner"
        />
      </div>

      {/* Table Container */}
      <div className="overflow-hidden border border-slate-100 rounded-2xl bg-white shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50/80 text-slate-400 uppercase text-[10px] font-black tracking-[0.15em]">
              <tr>
                <th className="px-8 py-5">Full Name</th>
                <th className="px-8 py-5">Contact Details</th>
                <th className="px-8 py-5">Status</th>
                <th className="px-8 py-5">Check-in Time</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {!loading && filteredAttendees.map(a => (
                <tr key={a.id} className="hover:bg-indigo-50/20 transition-colors">
                  <td className="px-8 py-6">
                    <div className="font-bold text-slate-700 text-sm capitalize">{a.firstName} {a.lastName}</div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="text-xs font-bold text-slate-500">{a.email}</div>
                    <div className="text-[10px] text-slate-400 font-medium mt-1">{a.phone}</div>
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-wider ${a.category === 'Member' ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'}`}>
                      {a.category}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-[10px] font-bold text-slate-400">
                    {a.createdAt?.toDate() ? a.createdAt.toDate().toLocaleString([], { hour: '2-digit', minute: '2-digit', day: '2-digit', month: 'short' }) : '---'}
                  </td>
                </tr>
              ))}

              {loading && <tr><td colSpan={4} className="py-32 text-center">
                <i className="fa-solid fa-spinner animate-spin text-3xl text-indigo-200"></i>
              </td></tr>}

              {!loading && filteredAttendees.length === 0 && (
                <tr><td colSpan={4} className="py-32 text-center">
                  <div className="flex flex-col items-center gap-4">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-200">
                      <i className="fa-solid fa-user-slash text-xl"></i>
