            <h3 className="text-2xl font-black text-slate-800 mb-3">Destructive Action</h3>
            <p className="text-slate-500 font-medium mb-8 leading-relaxed">
              You are about to permanently delete <span className="text-red-600 font-black">{attendees.length} records</span>. This action is irreversible and will wipe the entire attendance database.
            </p>

            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Type "DELETE" to confirm</label>
                <input
                  type="text"
                  value={deleteConfirmText}
                  onChange={(e) => setDeleteConfirmText(e.target.value.toUpperCase())}
                  placeholder="Type DELETE here"
                  className="w-full px-6 py-5 rounded-2xl bg-slate-50 border-2 border-transparent focus:border-red-100 text-red-600 outline-none transition-all font-black text-center tracking-widest placeholder:font-bold placeholder:text-slate-200"
                  autoFocus
                />
              </div>

              <div className="flex gap-4">
                <button
                  onClick={() => setIsDeleteModalOpen(false)}
                  className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black hover:bg-slate-200 transition-all uppercase tracking-widest text-sm"
                >
                  Cancel
                </button>
                <button
                  onClick={executeClearAll}
                  disabled={deleteConfirmText !== 'DELETE'}
                  className="flex-[2] py-5 bg-red-500 text-white rounded-2xl font-black hover:bg-red-600 transition-all shadow-xl shadow-red-200 active:scale-95 disabled:opacity-30 disabled:cursor-not-allowed uppercase tracking-widest text-sm"
                >
                  Clear Database
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-2xl p-8 md:p-12 border border-white/60 animate-fade-in">
        {/* Header & Stats */}
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
          <div>
            <h2 className="text-5xl font-black text-slate-800 tracking-tighter">Admin Portal</h2>
            <div className="flex flex-wrap items-center gap-4 mt-4">
              <div className="flex items-center gap-2 bg-indigo-50 px-4 py-2 rounded-full border border-indigo-100">
                <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                <span className="text-[11px] font-black text-indigo-600 uppercase tracking-wider">{attendees.length} Total</span>
              </div>
              <div className="flex items-center gap-2 bg-green-50 px-4 py-2 rounded-full border border-green-100">
                <span className="text-[11px] font-black text-green-600 uppercase tracking-wider">{stats.members} Members</span>
              </div>
              <div className="flex items-center gap-2 bg-orange-50 px-4 py-2 rounded-full border border-orange-100">
                <span className="text-[11px] font-black text-orange-600 uppercase tracking-wider">{stats.guests} Guests</span>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap gap-4 w-full lg:w-auto">
            <button onClick={copyEmails} className="flex-1 lg:flex-none p-4 px-6 bg-slate-50 rounded-2xl hover:bg-slate-100 text-slate-600 font-black text-[11px] transition-all flex items-center justify-center gap-2 uppercase tracking-widest">
              <i className="fa-solid fa-envelope"></i> Copy Emails
            </button>
            <button onClick={() => setIsExportModalOpen(true)} className="flex-1 lg:flex-none p-4 px-6 bg-indigo-600 text-white rounded-2xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all text-[11px] flex items-center justify-center gap-2 uppercase tracking-widest">
              <i className="fa-solid fa-file-export"></i> Export CSV
            </button>
            <button 
              onClick={initiateClearAll} 
              disabled={actionLoading || attendees.length === 0} 
              className="flex-1 lg:flex-none p-4 px-6 bg-red-500 text-white rounded-2xl font-black hover:bg-red-600 shadow-xl shadow-red-100 transition-all text-[11px] flex items-center justify-center gap-2 uppercase tracking-widest disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {actionLoading ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-trash-can"></i>} Clear All
            </button>
          </div>
        </div>

        {fetchError && (
          <div className="mb-8 p-5 bg-red-50 border border-red-100 text-red-600 rounded-2xl text-xs font-bold flex items-center gap-3 animate-shake">
            <i className="fa-solid fa-triangle-exclamation text-lg"></i>
            {fetchError}
          </div>
        )}

        {/* Search Bar */}
        <div className="relative mb-10 group">
          <i className="fa-solid fa-magnifying-glass absolute left-8 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors text-lg"></i>
          <input 
            type="text" 
            placeholder="Search database by name, email or phone..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-16 pr-8 py-6 rounded-3xl bg-slate-50 border-2 border-transparent focus:border-indigo-100 focus:bg-white text-slate-700 outline-none transition-all font-bold placeholder:text-slate-300 placeholder:font-medium shadow-inner text-lg"
          />
        </div>

        {/* Table Container */}
        <div className="overflow-hidden border border-slate-100 rounded-3xl bg-white shadow-inner">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50/50 text-slate-400 uppercase text-[10px] font-black tracking-[0.2em]">
                <tr>
                  <th className="px-10 py-6">Full Name</th>
                  <th className="px-10 py-6">Contact Details</th>
                  <th className="px-10 py-6">Status</th>
                  <th className="px-10 py-6">Check-in Time</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {!loading && filteredAttendees.map(a => (
                  <tr key={a.id} className="hover:bg-indigo-50/20 transition-all duration-300">
                    <td className="px-10 py-7">
                      <div className="font-black text-slate-700 text-base capitalize">{a.firstName} {a.lastName}</div>
                    </td>
                    <td className="px-10 py-7">
                      <div className="text-sm font-bold text-slate-500">{a.email}</div>
                      <div className="text-[11px] text-slate-400 font-medium mt-1.5 flex items-center gap-2">
                        <i className="fa-solid fa-phone text-[9px]"></i> {a.phone}
                      </div>
                    </td>
                    <td className="px-10 py-7">
                      <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest inline-block ${a.category === 'Member' ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'}`}>
                        {a.category}
                      </span>
                    </td>
                    <td className="px-10 py-7 text-[11px] font-bold text-slate-400 whitespace-nowrap">
                      {a.createdAt?.toDate ? a.createdAt.toDate().toLocaleString([], { hour: '2-digit', minute: '2-digit', day: '2-digit', month: 'short', year: 'numeric' }) : '---'}
                    </td>
                  </tr>
                ))}

                {(loading || actionLoading) && <tr><td colSpan={4} className="py-40 text-center">
                  <div className="flex flex-col items-center gap-4">
                    <i className="fa-solid fa-spinner animate-spin text-5xl text-indigo-200"></i>
                    <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Processing Records</p>
                  </div>
                </td></tr>}

                {!loading && !actionLoading && filteredAttendees.length === 0 && (
                  <tr><td colSpan={4} className="py-40 text-center">
                    <div className="flex flex-col items-center gap-5">
                      <div className="w-24 h-24 bg-slate-50 rounded-[2.5rem] flex items-center justify-center text-slate-200 rotate-6 shadow-inner">
                        <i className="fa-solid fa-database text-3xl"></i>
                      </div>
                      <div>
                        <h4 className="text-xl font-black text-slate-300">Empty Dataset</h4>
                        <p className="text-[10px] font-black text-slate-200 uppercase tracking-widest mt-1">No matching attendance records found</p>
                      </div>
                    </div>
                  </td></tr>
                )}
