        </div>
        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center bg-slate-50 text-slate-400 shadow-inner`}>
          <i className={`fa-solid ${icon} text-lg`}></i>
        </div>
      </div>
    </div>
