import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase/config';

const ADMIN_PASSWORD = 'IGANDO_ADMIN_2025';

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [authError, setAuthError] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  // Advanced Filters
  const [filterSex, setFilterSex] = useState<string>('All');
  const [filterAge, setFilterAge] = useState<string>('All');
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [filterLocation, setFilterLocation] = useState<string>('All');

  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (isAuthenticated) {
      setLoading(true);
      const attendanceRef = collection(db, 'attendance');
      const q = query(attendanceRef, orderBy('createdAt', 'desc'));

      const unsubscribe = onSnapshot(q, (snapshot) => {
        const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        setAttendees(data);
        setLastUpdated(new Date());
        setLoading(false);
      }, (error) => {
        console.error("Firestore error:", error);
        setLoading(false);
      });
      return () => unsubscribe();
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      showToast("Access Granted", "success");
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  // Real-time Summary Stats
  const stats = useMemo(() => {
    return {
      total: attendees.length,
      guests: attendees.filter(a => a.category === 'First Timer/Guest').length,
      returning: attendees.filter(a => a.category === 'Revisiting/Returning Member').length,
      members: attendees.filter(a => a.category === 'Member').length,
    };
  }, [attendees]);

  const filteredAttendees = useMemo(() => {
    return attendees.filter(a => {
      const matchesSearch = !searchQuery.trim() || 
        `${a.firstName} ${a.lastName}`.toLowerCase().includes(searchQuery.toLowerCase()) ||
        a.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        a.phone?.includes(searchQuery);

      const matchesSex = filterSex === 'All' || a.sex === filterSex;
      const matchesAge = filterAge === 'All' || a.ageRange === filterAge;
      const matchesCategory = filterCategory === 'All' || a.category === filterCategory;
      const matchesLocation = filterLocation === 'All' || a.location === filterLocation;

      return matchesSearch && matchesSex && matchesAge && matchesCategory && matchesLocation;
    });
  }, [attendees, searchQuery, filterSex, filterAge, filterCategory, filterLocation]);

  const downloadCSV = () => {
    if (filteredAttendees.length === 0) {
      showToast("No data to export", "error");
      return;
    }

    const escapeCsv = (val: any) => {
      if (val === undefined || val === null) return '""';
      const str = String(val).replace(/"/g, '""');
      return `"${str}"`;
    };

    const headers = [
      'First Name', 'Last Name', 'Email Address', 'Phone Number', 
      'Sex', 'Age Range', 'Category', 'Location', 'Date Registered'
    ];

    const rows = filteredAttendees.map(a => [
      escapeCsv(a.firstName),
      escapeCsv(a.lastName),
      escapeCsv(a.email),
      escapeCsv(a.phone),
      escapeCsv(a.sex),
      escapeCsv(a.ageRange),
      escapeCsv(a.category),
      escapeCsv(a.location),
      a.createdAt?.toDate ? a.createdAt.toDate().toLocaleString() : 'N/A'
    ]);

    const csvContent = "\uFEFF" + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `tcn_igando_attendance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
    showToast(`Exported ${filteredAttendees.length} records`);
  };

  const StatCard = ({ title, count, colorClass, icon, bgGradient }: { title: string, count: number, colorClass: string, icon: string, bgGradient: string }) => (
    <div className={`relative bg-white p-6 rounded-[2.5rem] shadow-xl overflow-hidden group transition-all hover:-translate-y-1 hover:shadow-2xl`}>
      <div className={`absolute top-0 right-0 w-32 h-32 -mr-8 -mt-8 rounded-full blur-3xl opacity-10 ${bgGradient}`}></div>
      <div className="flex justify-between items-start relative z-10">
        <div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">{title}</p>
          <h3 className="text-4xl font-black text-slate-900 tracking-tight">{count.toLocaleString()}</h3>
        </div>
        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center bg-slate-50 text-slate-400 shadow-inner group-hover:bg-white group-hover:scale-110 transition-transform duration-500`}>
          <i className={`fa-solid ${icon} text-xl ${colorClass}`}></i>
        </div>
      </div>
      <div className={`mt-4 h-1 w-12 rounded-full ${bgGradient.split(' ')[0]}`}></div>
    </div>
  );

  if (!isAuthenticated) {
    return (
      <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 text-center relative overflow-hidden border border-white/60 mx-auto mt-20">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
        <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 rotate-6 shadow-xl border-4 border-white">
          <i className="fa-solid fa-vault text-4xl"></i>
        </div>
        <h2 className="text-3xl font-black text-slate-800 mb-2 tracking-tighter">Command Center</h2>
        <p className="text-slate-400 font-medium mb-10 text-sm">Enter the system clearance password</p>
        <form onSubmit={handleLogin} className="space-y-4">
          <div className="relative">
            <input
              type={showPassword ? "text" : "password"}
              value={passwordInput}
              onChange={(e) => setPasswordInput(e.target.value)}
              placeholder="••••••••"
              className={`w-full px-8 py-5 rounded-2xl bg-slate-50 text-slate-700 outline-none focus:ring-4 focus:ring-indigo-100 font-black text-center tracking-[0.5em] text-xl transition-all ${authError ? 'ring-4 ring-red-100 border-red-200' : 'border-slate-100'}`}
            />
            <button 
              type="button" 
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-300 hover:text-indigo-500 transition-colors"
            >
              <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
            </button>
          </div>
          <button type="submit" className="w-full py-5 bg-[#5C6BC0] text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-indigo-100 transition-all hover:bg-indigo-700 hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-3">
            <i className="fa-solid fa-fingerprint text-xl"></i> Verify Identity
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="w-full max-w-7xl relative px-4 pb-20 mx-auto">
      {toast && (
        <div className="fixed top-8 left-1/2 -translate-x-1/2 z-[110] px-8 py-4 bg-white/90 backdrop-blur-md rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.1)] border border-white flex items-center gap-4 animate-bounce-in">
          <div className={`w-10 h-10 rounded-full flex items-center justify-center shadow-lg ${toast.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
            <i className={`fa-solid ${toast.type === 'success' ? 'fa-check' : 'fa-xmark'} text-lg`}></i>
          </div>
          <span className="text-sm font-black text-slate-800 uppercase tracking-widest">{toast.message}</span>
        </div>
      )}

      {/* Header with real-time indicator */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-10">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <span className="px-3 py-1 bg-indigo-100 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest animate-pulse">Live Feed</span>
            <p className="text-slate-400 text-xs font-bold">Last synced: {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</p>
          </div>
          <h2 className="text-5xl lg:text-6xl font-black text-slate-900 tracking-tighter">Analytics <span className="text-indigo-600">Hub</span></h2>
        </div>
        <button 
          onClick={downloadCSV} 
          className="group relative px-10 py-5 bg-slate-900 text-white rounded-[2rem] font-black uppercase tracking-widest shadow-2xl transition-all hover:bg-indigo-600 active:scale-95 flex items-center justify-center gap-3 overflow-hidden"
        >
           <span className="relative z-10 flex items-center gap-3">
             <i className="fa-solid fa-cloud-arrow-down text-xl group-hover:bounce"></i> Export Registry
           </span>
           <div className="absolute inset-0 bg-gradient-to-r from-indigo-600 to-purple-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>
        </button>
      </div>

      {/* Summary Stats Section */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
        <StatCard title="Total Registry" count={stats.total} colorClass="text-indigo-500" icon="fa-chart-pie" bgGradient="bg-indigo-500" />
        <StatCard title="First-Time Guests" count={stats.guests} colorClass="text-orange-500" icon="fa-fire" bgGradient="bg-orange-500" />
        <StatCard title="Returning Members" count={stats.returning} colorClass="text-purple-500" icon="fa-heart" bgGradient="bg-purple-500" />
        <StatCard title="Active Members" count={stats.members} colorClass="text-emerald-500" icon="fa-id-badge" bgGradient="bg-emerald-500" />
      </div>

      <div className="bg-white/70 backdrop-blur-xl rounded-[3rem] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.1)] p-6 lg:p-12 border border-white relative overflow-hidden">
        {/* Search & Filter Toolbar */}
        <div className="space-y-6 mb-12">
          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex-1 relative group">
               <i className="fa-solid fa-magnifying-glass absolute left-8 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors text-xl"></i>
               <input 
                  type="text" 
                  placeholder="Quick search..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-16 pr-8 py-6 rounded-[2rem] bg-slate-100/50 border-2 border-transparent outline-none font-bold text-slate-800 placeholder:text-slate-400 focus:bg-white focus:border-indigo-100 focus:ring-4 focus:ring-indigo-50 transition-all text-xl shadow-inner"
               />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 lg:w-2/3">
               {[
