        </div>
        <button 
          onClick={downloadCSV} 
          className="group relative w-full md:w-auto px-6 md:px-10 py-4 md:py-5 bg-slate-900 text-white rounded-[0.6em] md:rounded-[2rem] font-black uppercase tracking-widest shadow-2xl transition-all hover:bg-indigo-600 active:scale-95 flex items-center justify-center gap-2 md:gap-3 overflow-hidden text-[10px] md:text-base"
