};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { collection, query, orderBy, onSnapshot } from 'firebase/firestore';
import { db } from '../firebase/config';

const ADMIN_PASSWORD = 'IGANDO_ADMIN_2025';

const AdminDashboard: React.FC = () => {
  const [attendees, setAttendees] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [authError, setAuthError] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  // Advanced Filters
  const [filterSex, setFilterSex] = useState<string>('All');
  const [filterAge, setFilterAge] = useState<string>('All');
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [filterLocation, setFilterLocation] = useState<string>('All');

  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (isAuthenticated) {
      setLoading(true);
      const attendanceRef = collection(db, 'attendance');
      const q = query(attendanceRef, orderBy('createdAt', 'desc'));

      const unsubscribe = onSnapshot(q, (snapshot) => {
        const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        setAttendees(data);
        setLastUpdated(new Date());
        setLoading(false);
      }, (error) => {
        console.error("Firestore error:", error);
        setLoading(false);
      });
      return () => unsubscribe();
    }
  }, [isAuthenticated]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === ADMIN_PASSWORD) {
      setIsAuthenticated(true);
      showToast("Access Granted", "success");
    } else {
      setAuthError(true);
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  // Real-time Summary Stats
  const stats = useMemo(() => {
    return {
      total: attendees.length,
      guests: attendees.filter(a => a.category === 'First Timer/Guest').length,
      returning: attendees.filter(a => a.category === 'Revisiting/Returning Member').length,
      members: attendees.filter(a => a.category === 'Member').length,
    };
  }, [attendees]);

  const filteredAttendees = useMemo(() => {
    return attendees.filter(a => {
      const matchesSearch = !searchQuery.trim() || 
        `${a.firstName} ${a.lastName}`.toLowerCase().includes(searchQuery.toLowerCase()) ||
        a.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        a.phone?.includes(searchQuery);

      const matchesSex = filterSex === 'All' || a.sex === filterSex;
      const matchesAge = filterAge === 'All' || a.ageRange === filterAge;
      const matchesCategory = filterCategory === 'All' || a.category === filterCategory;
      const matchesLocation = filterLocation === 'All' || a.location === filterLocation;

      return matchesSearch && matchesSex && matchesAge && matchesCategory && matchesLocation;
    });
  }, [attendees, searchQuery, filterSex, filterAge, filterCategory, filterLocation]);

  /**
   * Generates and triggers download of a CSV file containing 
   * all currently filtered/displayed records.
   */
  const downloadCSV = () => {
    if (filteredAttendees.length === 0) {
      showToast("No data to export", "error");
      return;
    }

    const escapeCsv = (val: any) => {
      if (val === undefined || val === null) return '""';
      // Ensure commas and quotes within data don't break the CSV structure
      const str = String(val).replace(/"/g, '""');
      return `"${str}"`;
    };

    const headers = [
      'First Name', 
      'Last Name', 
      'Email Address', 
      'Phone Number', 
      'Sex', 
      'Age Range', 
      'Category', 
      'Location', 
      'Date Registered'
    ];

    const rows = filteredAttendees.map(a => [
      escapeCsv(a.firstName),
      escapeCsv(a.lastName),
      escapeCsv(a.email),
      escapeCsv(a.phone),
      escapeCsv(a.sex),
      escapeCsv(a.ageRange),
      escapeCsv(a.category),
      escapeCsv(a.location),
      a.createdAt?.toDate ? a.createdAt.toDate().toLocaleString() : 'N/A'
    ]);

    // Using \uFEFF (BOM) to ensure Excel opens with UTF-8 encoding
    const csvContent = "\uFEFF" + [headers.join(','), ...rows.map(e => e.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `tcn_igando_attendance_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
    showToast(`Exported ${filteredAttendees.length} records`);
  };

  const StatCard = ({ title, count, colorClass, icon, bgGradient }: { title: string, count: number, colorClass: string, icon: string, bgGradient: string }) => (
    <div className={`relative bg-white p-4 md:p-6 rounded-[0.6em] md:rounded-[2.5rem] shadow-xl overflow-hidden group transition-all hover:-translate-y-1 hover:shadow-2xl`}>
