                 { value: filterLocation, setter: setFilterLocation, options: ['All Locations', 'Egbeda/Akowonjo', 'Iyana-Ipaja', 'Ikotun', 'Igando', 'Ijegun', 'Oke-Odo', 'Ayobo & Ipaja'], icon: 'fa-map-pin' }
               ].map((filter, idx) => (
