                   <i className={`fa-solid ${filter.icon} absolute left-3 md:left-4 top-1/2 -translate-y-1/2 text-slate-300 text-[8px] md:text-[10px] pointer-events-none group-hover/filter:text-indigo-400 transition-colors`}></i>
